/**
 * MinPriorityQueue implementation for Dijkstra's algorithm.
 * Stores [distance, node] tuples, prioritized by minimum distance.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Helper function to compare elements based on distance (index 0)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this._compare(index, parentIndex)) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Check left child
            if (leftChildIndex <= lastIndex && this._compare(leftChildIndex, smallest)) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && this._compare(rightChildIndex, smallest)) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                this._swap(index, smallest);
                index = smallest;
            } else {
                break;
            }
        }
    }

    enqueue(distance, node) {
        this.heap.push([distance, node]);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return min;
    }
}


/**
 * Solves the minimum cost problem.
 * @param {number} n Number of shops.
 * @param {bigint[]} prices Array of apple prices.
 * @param {number[][]} roads Array of road descriptions.
 * @returns {bigint[]} Array of minimum total costs for each shop.
