function solve(n, prices, roads) {
    // Convert prices to BigInt to handle large values
    const priceBigInts = prices.map(p => BigInt(p));

    // --- 1. Build Adjacency Lists for both scenarios ---

    // Adj_E: Empty-handed travel (weight = cost)
    const adjEmpty = Array(n).fill(0).map(() => []);

    // Adj_C: Carrying apples travel (weight = cost * tax)
    const adjCarry = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        const costBig = BigInt(cost);
        const taxBig = BigInt(tax);

        // Empty-handed travel (bidirectional)
        adjEmpty[u].push({ neighbor: v, weight: costBig });
        adjEmpty[v].push({ neighbor: u, weight: costBig });

        // Carrying apples travel (bidirectional)
        const carryWeight = costBig * taxBig;
        adjCarry[u].push({ neighbor: v, weight: carryWeight });
        adjCarry[v].push({ neighbor: u, weight: carryWeight });
    }

    // --- 2. Dijkstra's Algorithm Implementation ---

    /**
     * Runs Dijkstra's algorithm from a start node.
     * @param {number} startNode The starting shop index.
     * @param {Array<Array<{neighbor: number, weight: bigint}>>} adj The adjacency list.
     * @returns {bigint[]} Array of minimum distances from startNode to all other nodes.
     */
    const dijkstra = (startNode, adj) => {
        // Initialize distances to infinity (represented by a very large BigInt)
        const INF = 10n ** 18n * BigInt(n); // Sufficiently large number
        const dist = Array(n).fill(INF);
        dist[startNode] = 0n;

        const pq = new MinPriorityQueue();
        pq.enqueue(0n, startNode);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const weight = edge.weight;

                const newDist = d + weight;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.enqueue(newDist, v);
                }
            }
        }
        return dist;
    };

    // --- 3. Calculate All-Pairs Shortest Paths ---

    // DE[i][j] = min cost from i to j empty-handed
    const DE = []; 
    for (let i = 0; i < n; i++) {
        DE.push(dijkstra(i, adjEmpty));
    }

    // DC[i][j] = min cost from i to j carrying apples
    const DC = [];
    for (let i = 0; i < n; i++) {
        DC.push(dijkstra(i, adjCarry));
    }

    // --- 4. Determine Minimum Cost for each shop i ---

    const ans = Array(n).fill(0n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at shop i
        let minCost = priceBigInts[i];

        // Option 2: Travel i -> j (empty) + Buy at j + Travel j -> i (carrying)
        for (let j = 0; j < n; j++) {
            // Cost = D_E[i][j] + prices[j] + D_C[j][i]
            // Since D_C[j][i] = DC[j][i], we use the stored values.

            const costEmptyToJ = DE[i][j];
            const costCarryFromJToI = DC[j][i]; 

            // Check if paths exist (i.e., not INF)
            const INF = 10n ** 18n * BigInt(n);
            if (costEmptyToJ === INF || costCarryFromJToI === INF) {
                continue;
            }

            const totalCost = costEmptyToJ + priceBigInts[j] + costCarryFromJToI;

            if (totalCost < minCost) {
                minCost = totalCost;
            }
        }
        ans[i] = minCost;
    }

    // Convert BigInt results back to standard JS numbers or strings if necessary, 
    // but since the return type is implicitly based on the input structure, 
    // returning BigInt array is the safest practice given the constraints (up to 10^14).
    // Since JS standard practice for competitive programming usually implies standard numbers unless exceeding 2^53, 
    // and BigInt is required here for correctness, we return the array of BigInts.
    return ans.map(b => b.toString()); // Convert BigInt to string representation of the number for safe JS output if environment requires primitive type, but BigInt itself is safer. Let's stick to BigInt return type as per strict computation need.
}
// Adjusting return type handling: The prompt expects a length N integer array. 
// If the platform expects standard JS numbers, we risk overflow. Given constraints, BigInt is necessary. 
// Assuming the testing environment can handle BigInt results or string representation of large integers.
// For compatibility, I will return BigInt array.

/*
Final check on return format: "Return a length of n integer array ans"
If the environment supports BigInt, returning BigInt[] is fine. If it strictly requires Number[], then we must acknowledge overflow risk, but since the calculation demands BigInt, we stick to BigInt[] output.
*/
const solveWrapper = (n, prices, roads) => {
    const result = solve(n, prices, roads);
    // If the checker expects primitive numbers, this conversion might fail if values > 2^53
    // For safety in a typical CP setting, we map BigInts to strings if required, but sticking to BigInt output structure.
    return result;
}
// We must strictly adhere to the signature: function solve(n, prices, roads)
// The code above implements this signature.
return solve;

